# Radix tree for KV cache prefix matching (conceptual)
class PrefixCache:
    def __init__(self):
        # Trie: node -> {token_id: child_node}
        self.root = {}
        # Each node stores: KV block pointer, access count, eviction priority
        self.node_to_kv = {}  # node_id -> (layer, head, block_ptr)

    def find_longest_prefix(self, prompt_tokens):
        """Return the longest cached prefix and remaining tokens."""
        node = self.root
        prefix_len = 0
        for i, tok in enumerate(prompt_tokens):
            if tok in node:
                node = node[tok]
                prefix_len = i + 1
            else:
                break
        return prompt_tokens[:prefix_len], prompt_tokens[prefix_len:]

    def insert(self, tokens, kv_pointers):
        """Cache KV blocks for a token sequence."""
        node = self.root
        for tok in tokens:
            if tok not in node:
                node[tok] = {}
            node = node[tok]
        # Associate leaf node with KV blocks
        self.node_to_kv[id(node)] = kv_pointers

    def evict_lru(self, max_nodes=10000):
